#!/usr/bin/env bash
# Mock claudecode CLI for testing
# Simulates behavior of the real claudecode command

# Get skill name from arguments
# When called as: mock-claudecode.sh skill <skillname>
# $1 = "skill", $2 = skillname
SKILL_NAME="${2:-unknown-skill}"

# Check for error simulation modes via environment variables
if [ "$MOCK_TOKEN_EXPIRED" = "1" ]; then
  echo "Error: AWS SSO token has expired. Please run 'aws sso login'" >&2
  exit 1
fi

if [ "$MOCK_SKILL_NOT_FOUND" = "1" ]; then
  echo "Error: skill not found - '${SKILL_NAME}' does not exist" >&2
  exit 1
fi

if [ "$MOCK_COMMAND_ERROR" = "1" ]; then
  echo "Error: Command execution failed" >&2
  exit 1
fi

# Read stdin if available (PR context) - non-blocking
if [ -t 0 ]; then
  # stdin is a terminal (not piped), use default
  PR_CONTEXT="[No stdin provided]"
else
  # stdin is piped, read it
  PR_CONTEXT=$(cat)
fi

# Success mode - output a mock review
cat <<EOF
# Code Review for ${SKILL_NAME}

## Summary
This is a mock review generated by the test script.

## Files Reviewed
${PR_CONTEXT}

## Recommendations
- Everything looks good!
- This is a simulated review for testing purposes.

---
Generated by mock-claudecode.sh
EOF
